  ('medical-tech-moex-05257', 'medical-tech', 'medical-tech-moex-109-bccd9a5a', 'sub-medical-tech-05', NULL, 'single_choice', '有關lipopolysaccharides之敘述，下列何者錯誤？', '["O antigen、core polysaccharide及lipid A為主要成分", "革蘭氏陰性菌外膜的主要成分之一", "O antigen又稱somatic antigen", "lipid A可作為流行病學指紋鑑定"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:14:23+00:00", "source_pdf_sha1": "373261188af5", "answer_pdf_sha1": "c017dee462ea", "source_family": "moex-gov-tw", "moex": {"exam_code": "109020", "c": "308", "s": "44", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "微生物學與臨床微生物學（包括細菌與黴菌）", "year": "109", "exam_name": "109年第一次專技人員高等考試醫師牙醫師藥師考試分階段考試、醫事檢驗師、醫事放射師、物理治療師、職能治療師、呼吸治療師、獸醫師考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL)
